// ===== ⚙️ CONFIGURATION — MODIFIER ICI POUR LA MIGRATION EN PRODUCTION =====
var FE_URL      = 'http://localhost:4200';
var ADMIN_EMAIL = 'acq@bib.umontreal.ca';
var FROM_EMAIL  = 'chaine-achat@bib.umontreal.ca';
// =============================================================================

var TYPE_MAP = {
  "Suggestion d'achat - Usager": { label: "Suggestion d'achat",       color: '#7B4A15' },
  'Nouvel achat unique':          { label: 'Nouvel achat unique',       color: '#1B5E6E' },
  'Nouvel abonnement':            { label: 'Nouvel abonnement',         color: '#4C1D95' },
  'Modification et CCOL':         { label: 'Modification et CCOL',      color: '#3730A3' },
  'PEB Tipasa num\u00e9rique':         { label: 'PEB Tipasa num\u00e9rique',      color: '#3730A3' },
  'Requ\u00eate ACQ Accessibilit\u00e9':   { label: 'Requ\u00eate ACQ Accessibilit\u00e9', color: '#37424D' }
};

var inp = $input.first().json;
var d   = inp.body || inp;
var ti  = TYPE_MAP[d.type_formulaire] || { label: d.type_formulaire || 'Inconnu', color: '#37474F' };
var id  = d.id || d.reponse_id || '?';

// Structure backend (plate) : { baseData: {...}, specificData: {...} }
// Structure frontend (imbriqu\u00e9e) : { reponses: { baseData: {...}, specificData: {...} } }
var bd = d.baseData
      || (d.reponses && d.reponses.baseData ? d.reponses.baseData : (d.reponses || {}));
var sd = d.specificData
      || (d.reponses && d.reponses.specificData ? d.reponses.specificData : {});

// demandeur = champ formulaire ; usager_nom = admin connect\u00e9 (fallback)
var nom      = bd.demandeur    || d.usager_nom      || bd.nom      || '\u2014';
var courriel = bd.courriel     || d.usager_courriel || '\u2014';
var statut   = bd.statut       || d.usager_statut   || '\u2014';
var titre    = bd.titre_document || d.titre_document || '\u2014';
var auteur   = bd.auteur  || sd.auteur  || null;
var editeur  = bd.editeur || sd.editeur || '\u2014';
var isbn     = bd.isbn_issn || sd.isbn_issn || '\u2014';
var prio     = bd.priorite_demande || '\u2014';
var prixCad  = bd.prix_cad || sd.prix_cad || null;
var fonds    = bd.fonds_budgetaire || sd.fonds_budgetaire || null;
var note     = bd.note_commentaire || bd.note_usager || null;
var biblio   = bd.bibliotheque || '\u2014';
var acqLink  = FE_URL + '/acq-decision?id=' + id;
var c        = ti.color;

var now = new Date().toLocaleString('fr-CA', {
  timeZone: 'America/Toronto',
  year: 'numeric', month: 'long', day: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

var badge = function(p) {
  var lp = (p || '').toLowerCase();
  if (lp === 'urgent')      return "<span style='background:#fdecea;color:#b72600;padding:2px 10px;border-radius:4px;font-size:11px;font-weight:700'>URGENT</span>";
  if (lp === 'prioritaire') return "<span style='background:#fff3e0;color:#e65100;padding:2px 10px;border-radius:4px;font-size:11px;font-weight:700'>PRIORITAIRE</span>";
  return "<span style='background:#e8f5e9;color:#2e7d32;padding:2px 10px;border-radius:4px;font-size:11px;font-weight:700'>R\u00c9GULIER</span>";
};

var data = [
  ['R\u00e9f.',         '#' + id],
  ['Date',         now],
  ['Demandeur',    nom],
  ['Courriel',     courriel],
  ['Statut',       statut],
  ['Biblioth\u00e8que',  biblio],
  ['Titre',        '<strong>' + titre + '</strong>'],
  [auteur ? 'Auteur' : '\u00c9diteur', auteur || editeur],
  ['ISBN / ISSN',  isbn],
  ['Priorit\u00e9',     badge(prio)]
];
if (prixCad) data.push(['Prix CAD', '$' + prixCad]);
if (fonds)   data.push(['Fonds',    fonds]);
if (note)    data.push(['Note',     '<em>' + note + '</em>']);

var rows = '';
data.forEach(function(r) {
  rows += "<tr>" +
    "<td style='padding:9px 0;border-bottom:1px solid #eaedf0;color:#607386;font-size:11px;text-transform:uppercase;letter-spacing:.5px;font-weight:700;width:155px;vertical-align:top'>" + r[0] + "</td>" +
    "<td style='padding:9px 0 9px 16px;border-bottom:1px solid #eaedf0;color:#343a40;font-size:14px'>" + r[1] + "</td>" +
    "</tr>";
});

var html =
  "<!DOCTYPE html><html lang='fr'><head><meta charset='UTF-8'><title>Nouvelle demande</title></head>" +
  "<body style='margin:0;padding:0;background:#f0f2f5;font-family:Segoe UI,Arial,sans-serif'>" +
  "<table width='100%' cellpadding='0' cellspacing='0' style='background:#f0f2f5;padding:32px 16px'><tr><td align='center'>" +
  "<table width='640' cellpadding='0' cellspacing='0' style='max-width:640px;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.10)'>" +
"<tr><td style='background:#1E2631;padding:28px 36px 0;border-bottom:4px solid " + c + "'>" +
"<p style='margin:0 0 5px;color:rgba(255,255,255,.50);font-size:10px;text-transform:uppercase;letter-spacing:1.4px'>Nouvelle demande \u2014 Biblioth\u00e8ques UdeM</p>" +
"<h1 style='margin:0 0 5px;color:#fff;font-size:20px;font-weight:600'>" + ti.label + "</h1>" +
"<p style='margin:0 0 20px;color:rgba(255,255,255,.55);font-size:12px'>Cha\u00eene d\u2019acquisitions \u2014 R\u00e9f. <strong style=\"color:rgba(255,255,255,.75)\">#" + id + "</strong></p>" +
"</td></tr>" +
  "<tr><td style='padding:26px 36px 8px'>" +
  "<p style='margin:0 0 18px;color:#607386;font-size:13px'>Un formulaire a \u00e9t\u00e9 soumis et requ\u00e9rit votre traitement.</p>" +
  "<table width='100%' cellpadding='0' cellspacing='0'>" + rows + "</table>" +
  "</td></tr>" +
  "<tr><td style='padding:24px 36px 30px;text-align:center'>" +
  "<p style='margin:0 0 16px;color:#9DABB9;font-size:12px'>Acc\u00e9der au formulaire de d\u00e9cision ACQ :</p>" +
  "<a href='" + acqLink + "' style='display:inline-block;background:" + c + ";color:#fff;padding:14px 40px;border-radius:8px;text-decoration:none;font-weight:700;font-size:15px'>Traiter la demande &#8594;</a>" +
  "<p style='font-size:11px;color:#c0c8d0;margin:12px 0 0;word-break:break-all'>" + acqLink + "</p>" +
  "</td></tr>" +
  "<tr><td style='background:#f8f9fa;padding:14px 36px;text-align:center;border-top:1px solid #eaedf0'>" +
  "<p style='margin:0;font-size:11px;color:#9DABB9'>Biblioth\u00e8ques \u2014 Universit\u00e9 de Montr\u00e9al &nbsp;&middot;&nbsp; Syst\u00e8me de gestion des acquisitions<br>Ce courriel est g\u00e9n\u00e9r\u00e9 automatiquement.</p>" +
  "</td></tr></table></td></tr></table></body></html>";

return [{ json: {
  ADMIN_EMAIL: ADMIN_EMAIL,
  FROM_EMAIL: FROM_EMAIL,
  emailSubject: '[ACQ UdeM] ' + ti.label + ' \u2014 ' + titre.substring(0, 55) + ' | #' + id,
  emailHtml: html
} }];

// ===== ⚙️ CONFIGURATION — MODIFIER ICI POUR LA MIGRATION EN PRODUCTION =====
var FROM_EMAIL = 'chaine-achat@bib.umontreal.ca';
// =============================================================================

var TYPE_MAP = {
  "Suggestion d'achat - Usager": { label: "Suggestion d'achat",       color: '#9B6B1A' },
  'Nouvel achat unique':          { label: 'Nouvel achat unique',       color: '#2A9086' },
  'Nouvel abonnement':            { label: 'Nouvel abonnement',         color: '#1B6B50' },
  'Modification et CCOL':         { label: 'Modification et CCOL',      color: '#3730A3' },
  'PEB Tipasa num\u00e9rique':         { label: 'PEB Tipasa num\u00e9rique',      color: '#C04A00' },
  'Requ\u00eate ACQ Accessibilit\u00e9':   { label: 'Requ\u00eate ACQ Accessibilit\u00e9', color: '#5B3D8A' }
};

var inp       = $input.first().json;
var d         = inp.body || inp;
var typeKey   = d.type_formulaire || 'Inconnu';
var ti        = TYPE_MAP[typeKey] || { label: typeKey, color: '#1E2631' };
var id        = d.reponse_id || '?';
var userEmail = d.usager_courriel || '';
var userNom   = d.usager_nom || 'Madame/Monsieur';
var titre     = d.titre_document || '\u2014';
var suiviAcq  = d.suivi_acq || '\u2014';
var noteAcq   = d.note_acq || null;
var c         = ti.color;

var noteRow = '';
if (noteAcq) {
  noteRow =
    "<tr><td style='padding:13px 18px;background:#f8f9fa;border-top:1px solid #eaedf0'>" +
    "<p style='margin:0 0 3px;color:#607386;font-size:10px;text-transform:uppercase;letter-spacing:.5px;font-weight:500'>Note / Commentaire</p>" +
    "<p style='margin:0;color:#607386;font-size:13px;font-style:italic'>" + noteAcq + "</p>" +
    "</td></tr>";
}

var html =
  "<!DOCTYPE html><html lang='fr'><head><meta charset='UTF-8'><title>Votre demande est prise en consid\u00e9ration</title></head>" +
  "<body style='margin:0;padding:0;background:#f0f2f5;font-family:Segoe UI,Arial,sans-serif'>" +
  "<table width='100%' cellpadding='0' cellspacing='0' style='background:#f0f2f5;padding:32px 16px'><tr><td align='center'>" +
  "<table width='620' cellpadding='0' cellspacing='0' style='max-width:620px;background:#fff;border-radius:10px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,.08)'>" +

  "<tr><td style='background:#1E2631;padding:28px 36px 0;border-bottom:4px solid " + c + "'>" +
  "<p style='margin:0 0 5px;color:rgba(255,255,255,.50);font-size:10px;text-transform:uppercase;letter-spacing:1.4px'>Biblioth\u00e8ques \u2014 Universit\u00e9 de Montr\u00e9al</p>" +
  "<h1 style='margin:0 0 20px;color:#fff;font-size:20px;font-weight:600'>Votre demande est prise en consid\u00e9ration</h1>" +
  "</td></tr>" +

  "<tr><td style='padding:26px 36px 8px'>" +
  "<p style='margin:0 0 4px;color:#343a40;font-size:14px;line-height:1.6'>Bonjour <strong>" + userNom + "</strong>,</p>" +
  "<p style='margin:0 0 22px;color:#607386;font-size:13px;line-height:1.6'>Nous avons bien re\u00e7u et trait\u00e9 votre demande d\u2019acquisition. Voici le r\u00e9sum\u00e9 du traitement\u00a0:</p>" +

  "<table width='100%' cellpadding='0' cellspacing='0' style='border:1px solid #eaedf0;border-radius:8px;overflow:hidden;margin-bottom:22px'>" +
  "<tr><td style='padding:13px 18px;border-bottom:1px solid #eaedf0;background:#f8f9fa'>" +
  "<p style='margin:0 0 3px;color:#607386;font-size:10px;text-transform:uppercase;letter-spacing:.5px;font-weight:500'>Type de formulaire</p>" +
  "<p style='margin:0;color:" + c + ";font-size:13px;font-weight:500'>" + ti.label + "</p>" +
  "</td></tr>" +
  "<tr><td style='padding:13px 18px;border-bottom:1px solid #eaedf0;background:#f8f9fa'>" +
  "<p style='margin:0 0 3px;color:#607386;font-size:10px;text-transform:uppercase;letter-spacing:.5px;font-weight:500'>Document demand\u00e9</p>" +
  "<p style='margin:0;color:#343a40;font-size:13px;font-weight:500'>" + titre + "</p>" +
  "</td></tr>" +
  "<tr><td style='padding:13px 18px;" + (noteAcq ? 'border-bottom:1px solid #eaedf0;' : '') + "background:#f8f9fa'>" +
  "<p style='margin:0 0 3px;color:#607386;font-size:10px;text-transform:uppercase;letter-spacing:.5px;font-weight:500'>ACQ \u2014 Suivi de la demande</p>" +
  "<p style='margin:0;color:#343a40;font-size:13px;font-weight:500'>" + suiviAcq + "</p>" +
  "</td></tr>" +
  noteRow +
  "</table>" +

  "<p style='margin:0 0 24px;color:#9DABB9;font-size:12px;line-height:1.6'>Pour toute question, veuillez contacter le Service des acquisitions de votre biblioth\u00e8que.</p>" +
  "</td></tr>" +

  "<tr><td style='background:#f8f9fa;padding:12px 36px;text-align:center;border-top:1px solid #eaedf0'>" +
  "<p style='margin:0;font-size:11px;color:#9DABB9'>Biblioth\u00e8ques \u2014 Universit\u00e9 de Montr\u00e9al &nbsp;&middot;&nbsp; Syst\u00e8me de gestion des acquisitions<br>Ce courriel est g\u00e9n\u00e9r\u00e9 automatiquement.</p>" +
  "</td></tr></table></td></tr></table></body></html>";

return [{ json: {
  FROM_EMAIL: FROM_EMAIL,
  userEmail: userEmail,
  emailSubject: '[Biblioth\u00e8ques UdeM] Votre demande est prise en consid\u00e9ration \u2014 ' + titre.substring(0, 50),
  emailHtml: html
} }];
